// MARK: - Session Delegate for SSL Handling

class NetworkSessionDelegate: NSObject, URLSessionDelegate, URLSessionTaskDelegate {
    
    private let trustedDomains: Set<String> = ["legacy.internal"]
    
    func urlSession(_ session: URLSession,
                    didReceive challenge: URLAuthenticationChallenge,
                    completionHandler: @escaping (URLSession.AuthChallengeDisposition, URLCredential?) -> Void) {
        
        guard let serverTrust = challenge.protectionSpace.serverTrust,
              let host = challenge.protectionSpace.host as String? else {
            completionHandler(.cancelAuthenticationChallenge, nil)
            return
        }
        
        // For legacy internal domains, accept the server's certificate
        if trustedDomains.contains(host) {
            let credential = URLCredential(trust: serverTrust)
            completionHandler(.useCredential, credential)
            return
        }
        
        // For all other domains, use default handling (system trust evaluation)
        completionHandler(.performDefaultHandling, nil)
    }
    
    func urlSession(_ session: URLSession,
                    task: URLSessionTask,
                    didReceive challenge: URLAuthenticationChallenge,
                    completionHandler: @escaping (URLSession.AuthChallengeDisposition, URLCredential?) -> Void) {
        
        guard let serverTrust = challenge.protectionSpace.serverTrust,
              let host = challenge.protectionSpace.host as String? else {
            completionHandler(.cancelAuthenticationChallenge, nil)
            return
        }
        
        if trustedDomains.contains(host) {
            let credential = URLCredential(trust: serverTrust)
            completionHandler(.useCredential, credential)
            return
        }
        
        completionHandler(.performDefaultHandling, nil)
    }
}

// MARK: - Network Manager

class NetworkManager {
    
    static let shared = NetworkManager()
    
    private let secureSession: URLSession
    private let legacySession: URLSession
    private let sessionDelegate: NetworkSessionDelegate
    
    private init() {
        sessionDelegate = NetworkSessionDelegate()
        
        // Secure session configuration for api.example.com
        let secureConfig = URLSessionConfiguration.default
        secureConfig.timeoutIntervalForRequest = 30
        secureConfig.timeoutIntervalForResource = 60
        secureConfig.httpAdditionalHeaders = [
            "Content-Type": "application/json",
            "Accept": "application/json"
        ]
        secureConfig.tlsMinimumSupportedProtocolVersion = .TLSv12
        secureSession = URLSession(configuration: secureConfig)
        
        // Legacy session configuration for legacy.internal
        let legacyConfig = URLSessionConfiguration.default
        legacyConfig.timeoutIntervalForRequest = 60
        legacyConfig.timeoutIntervalForResource = 120
        legacyConfig.httpAdditionalHeaders = [
            "Content-Type": "application/json",
            "Accept": "application/json"
        ]
        legacySession = URLSession(configuration: legacyConfig, delegate: sessionDelegate, delegateQueue: nil)
    }
    
    // MARK: - Generic Request Method
    
    func request<T: Codable>(
        environment: APIEnvironment,
        endpoint: String,
        method: String = "GET",
        body: Data? = nil,
        headers: [String: String]? = nil,
        completion: @escaping (Result<T, NetworkError>) -> Void
    ) {
        let urlString = "\(environment.baseURL)\(endpoint)"
        
        guard let url = URL(string: urlString) else {
            completion(.failure(.invalidURL))
            return
        }
        
        var request = URLRequest(url: url)
        request.httpMethod = method
        request.httpBody = body
        
        headers?.forEach { key, value in
            request.setValue(value, forHTTPHeaderField: key)
        }
        
        let session: URLSession
        switch environment {
        case .secure:
            session = secureSession
        case .legacy:
            session = legacySession
        }
        
        let task = session.dataTask(with: request) { data, response, error in
            if let error = error {
                let nsError = error as NSError
                if nsError.domain == NSURLErrorDomain &&
                    (nsError.code == NSURLErrorSecureConnectionFailed ||
                     nsError.code == NSURLErrorServerCertificateUntrusted) {
                    completion(.failure(.sslError))
                    return
                }
                completion(.failure(.networkError(error)))
                return
            }
            
            guard let httpResponse = response as? HTTPURLResponse else {
                completion(.failure(.unknownError))
                return
            }
            
            guard (200...299).contains(httpResponse.statusCode) else {
                completion(.failure(.serverError(httpResponse.statusCode)))
                return
            }
            
            guard let data = data else {
                completion(.failure(.noData))
                return
            }
            
            do {
                let decoder = JSONDecoder()
                decoder.keyDecodingStrategy = .convertFromSnakeCase
                let result = try decoder.decode(T.self, from: data)
                completion(.success(result))
            } catch {
                completion(.failure(.decodingError(error)))
            }
        }
        
        task.resume()
    }
    
    // MARK: - Async/Await Support
    
    @available(iOS 15.0, *)
    func request<T: Codable>(
        environment: APIEnvironment,
        endpoint: String,
        method: String = "GET",
        body: Data? = nil,
        headers: [String: String]? = nil
    ) async throws -> T {
        let urlString = "\(environment.baseURL)\(endpoint)"
        
        guard let url = URL(string: urlString) else {
            throw NetworkError.invalidURL
        }
        
        var request = URLRequest(url: url)
        request.httpMethod = method
        request.httpBody = body
        
        headers?.forEach { key, value in
            request.setValue(value, forHTTPHeaderField: key)
        }
        
        let session: URLSession
        switch environment {
        case .secure:
            session = secureSession
        case .legacy:
            session = legacySession
        }
        
        do {
            let (data, response) = try await session.data(for: request)
            
            guard let httpResponse = response as? HTTPURLResponse else {
                throw NetworkError.unknownError
            }
            
            guard (200...299).contains(httpResponse.statusCode) else {
                throw NetworkError.serverError(httpResponse.statusCode)
            }
            
            let decoder = JSONDecoder()
            decoder.keyDecodingStrategy = .convertFromSnakeCase
            return try decoder.decode(T.self, from: data)
        } catch let error as NetworkError {
            throw error
        } catch let error as DecodingError {
            throw NetworkError.decodingError(error)
        } catch {
            let nsError = error as NSError
            if nsError.domain == NSURLErrorDomain &&
                (nsError.code == NSURLErrorSecureConnectionFailed ||
                 nsError.code == NSURLErrorServerCertificateUntrusted) {
                throw NetworkError.sslError
            }
            throw NetworkError.networkError(error)
        }
