// MARK: - API Service

class APIService {
    
    private let networkManager = NetworkManager.shared
    
    // MARK: - Secure API Methods (api.example.com)
    
    func fetchUsers(completion: @escaping (Result<APIResponse<[User]>, NetworkError>) -> Void) {
        networkManager.request(
            environment: .secure,
            endpoint: "/api/v1/users",
            completion: completion
        )
    }
    
    func createUser(name: String, email: String, completion: @escaping (Result<APIResponse<User>, NetworkError>) -> Void) {
        let body: [String: Any] = ["name": name, "email": email]
        guard let bodyData = try? JSONSerialization.data(withJSONObject: body) else {
            completion(.failure(.unknownError))
            return
        }
        
        networkManager.request(
            environment: .secure,
            endpoint: "/api/v1/users",
            method: "POST",
            body: bodyData,
            completion: completion
        )
    }
    
    // MARK: - Legacy System Methods (legacy.internal)
    
    func fetchLegacyRecords(completion: @escaping (Result<[LegacyRecord], NetworkError>) -> Void) {
        networkManager.request(
            environment: .legacy,
            endpoint: "/records",
            completion: completion
        )
    }
    
    func fetchLegacyRecord(id: String, completion: @escaping (Result<LegacyRecord, NetworkError>) -> Void) {
        networkManager.request(
            environment: .legacy,
            endpoint: "/records/\(id)",
            completion: completion
        )
