        let indicator = UIActivityIndicatorView(style: .large)
        indicator.translatesAutoresizingMaskIntoConstraints = false
        indicator.hidesWhenStopped = true
        return indicator
    }()
    
    private let resultTextView: UITextView = {
        let textView = UITextView()
        textView.translatesAutoresizingMaskIntoConstraints = false
        textView.isEditable = false
        textView.font = .monospacedSystemFont(ofSize: 12, weight: .regular)
        textView.layer.borderColor = UIColor.systemGray4.cgColor
        textView.layer.borderWidth = 1
        textView.layer.cornerRadius = 8
        return textView
    }()
    
    override func viewDidLoad() {
        super.viewDidLoad()
        setupUI()
        setupActions()
    }
    
    private func setupUI() {
        title = "API Client"
        view.backgroundColor = .systemBackground
        
        let stackView = UIStackView(arrangedSubviews: [statusLabel, secureButton, legacyButton, bothButton, activityIndicator, resultTextView])
        stackView.translatesAutoresizingMaskIntoConstraints = false
        stackView.axis = .vertical
        stackView.spacing = 16
        stackView.alignment = .fill
        
        view.addSubview(stackView)
        
        NSLayoutConstraint.activate([
            stackView.topAnchor.constraint(equalTo: view.safeAreaLayoutGuide.topAnchor, constant: 20),
            stackView.leadingAnchor.constraint(equalTo: view.leadingAnchor, constant: 20),
            stackView.trailingAnchor.constraint(equalTo: view.trailingAnchor, constant: -20),
            stackView.bottomAnchor.constraint(equalTo: view.safeAreaLayoutGuide.bottomAnchor, constant: -20),
            
            secureButton.heightAnchor.constraint(equalToConstant: 50),
            legacyButton.heightAnchor.constraint(equalToConstant: 50),
            bothButton.heightAnchor.constraint(equalToConstant: 50),
            resultTextView.heightAnchor.constraint(greaterThanOrEqualToConstant: 200)
        ])
    }
    
    private func setupActions() {
        secureButton.addTarget(self, action: #selector(fetchFromSecureAPI), for: .touchUpInside)
        legacyButton.addTarget(self, action: #selector(fetchFromLegacySystem), for: .touchUpInside)
        bothButton.addTarget(self, action: #selector(fetchFromBothSystems), for: .touchUpInside)
    }
    
    @objc private func fetchFromSecureAPI() {
        startLoading(status: "Connecting to https://api.example.com...")
        
        apiService.fetchUsers { [weak self] result in
            DispatchQueue.main.async {
                self?.stopLoading()
                switch result {
                case .success(let response):
                    self?.statusLabel.text = "✅ Secure API - Success"
                    self?.statusLabel.textColor = .systemGreen
                    self?.resultTextView.text = "Secure API Response:\n\(response)"
                case .failure(let error):
                    self?.statusLabel.text = "❌ Secure API - Error"
                    self?.statusLabel.textColor = .systemRed
                    self?.resultTextView.text = "Secure API Error:\n\(error.localizedDescription)\n\nNote: This is expected if api.example.com is not reachable."
                }
            }
        }
    }
    
    @objc private func fetchFromLegacySystem() {
        startLoading(status: "Connecting to http://legacy.internal...")
        
        apiService.fetchLegacyRecords { [weak self] result in
            DispatchQueue.main.async {
                self?.stopLoading()
                switch result {
                case .success(let records):
                    self?.statusLabel.text = "✅ Legacy System - Success"
                    self?.statusLabel.textColor = .systemGreen
                    self?.resultTextView.text = "Legacy Records:\n\(records)"
                case .failure(let error):
                    self?.statusLabel.text = "❌ Legacy System - Error"
                    self?.statusLabel.textColor = .systemRed
                    self?.resultTextView.text = "Legacy System Error:\n\(error.localizedDescription)\n\nNote: This is expected if legacy.internal is not reachable.\nATS exception is configured to allow HTTP for this domain."
                }
            }
        }
    }
    
    @objc private func fetchFromBothSystems() {
        startLoading(status: "Connecting to both systems...")
        
        let group = DispatchGroup()
        var secureResult: String = ""
        var legacyResult: String = ""
        
        group.enter()
        apiService.fetchUsers { result in
            switch result {
            case .success(let response):
                secureResult = "✅ Secure API: \(response)"
            case .failure(let error):
                secureResult = "❌ Secure API: \(error.localizedDescription)"
            }
            group.leave()
        }
        
        group.enter()
        apiService.fetchLegacyRecords { result in
            switch result {
            case .success(let records):
                legacyResult = "✅ Legacy System: \(records.count) records"
            case .failure(let error):
                legacyResult = "❌ Legacy System: \(error.localizedDescription)"
            }
            group.leave()
        }
        
        group.notify(queue: .main) { [weak self] in
            self?.stopLoading()
            self?.statusLabel.text = "Both requests completed"
            self?.statusLabel.textColor = .label
            self?.resultTextView.text = """
            === Both Systems Results ===
            
            \(secureResult)
            
            ---
            
            \(legacyResult)
            
            ---
            
            ATS Configuration:
            • api.example.com: HTTPS with TLS 1.2+ (secure)
            • legacy.internal: HTTP allowed (insecure exception)
            """
        }
    }
    
    private func startLoading(status: String) {
        activityIndicator.startAnimating()
        statusLabel.text = status
        statusLabel.textColor = .label
        secureButton.isEnabled = false
        legacyButton.isEnabled = false
        bothButton.isEnabled = false
        resultTextView.text = ""
    }
    
    private func stopLoading() {
        activityIndicator.stopAnimating()
        secureButton.isEnabled = true
        legacyButton.isEnabled = true
        bothButton.isEnabled = true
    }
}

// MARK: - App Delegate

@main
class AppDelegate: UIResponder, UIApplicationDelegate {
    
    var window: UIWindow?
    
    func application(_ application: UIApplication, didFinishLaunchingWithOptions launchOptions: [UIApplication.LaunchOptionsKey: Any]?) -> Bool {
        
        // Verify ATS configuration at launch
        verifyATSConfiguration()
        
        window = UIWindow(frame: UIScreen.main.bounds)
        let viewController = ViewController()
        let navigationController = UINavigationController(rootViewController: viewController)
        window?.rootViewController = navigationController
        window?.makeKeyAndVisible()
        
        return true
    }
    
    private func verifyATSConfiguration() {
        guard let infoPlist = Bundle.main.infoDictionary,
              let atsDict = infoPlist["NSAppTransportSecurity"] as? [String: Any] else {
            print("⚠️ Warning: NSAppTransportSecurity not found in Info.plist")
            print("⚠️ Please add the required ATS configuration for legacy.internal")
            return
        }
        
        if let arbitraryLoads = atsDict["NSAllowsArbitraryLoads"] as? Bool, arbitraryLoads {
            print("⚠️ Warning: NSAllowsArbitraryLoads is set to YES. Consider using per-domain exceptions instead.")
        }
        
        if let exceptionDomains = atsDict["NSExceptionDomains"] as? [String: Any] {
            print("ℹ️ ATS Exception Domains configured:")
            for (domain, config) in exceptionDomains {
                print("  • \(domain): \(config)")
            }
        }
        
        print("✅ ATS Configuration verified")
    }
}

// MARK: - Scene Delegate (for iOS 13+)

class SceneDelegate: UIResponder, UIWindowSceneDelegate {
    
    var window: UIWindow?
    
    func scene(_ scene: UIScene, willConnectTo session: UISceneSession, options connectionOptions: UIScene.ConnectionOptions) {
        guard let windowScene = (scene as? UIWindowScene) else { return }
        
        window = UIWindow(windowScene: windowScene)
        let viewController = ViewController()
        let navigationController = UINavigationController(rootViewController: viewController)
        window?.rootViewController = navigationController
        window?.makeKeyAndVisible()
    }
}